if (! function_exists('game_playthrough_runner')) {
    function game_playthrough_runner($commands, $return_transcript_only = null)
    {
        // Load the game engine
        require_once __DIR__ . '/text_adventure_game.php';
        
        $transcript = [];
        
        // Initialize game state first (call with 'new' to get fresh state)
        // The game engine ignores the command when state is 'new', so we do a separate init
        $initResult = text_adventure_game('new', 'look');
        $initParsed = json_decode($initResult, true);
        if (!$initParsed || !isset($initParsed['state'])) {
            return json_encode(['error' => 'Failed to initialize game']);
        }
        $state = $initParsed['state'];

        foreach ($commands as $i => $cmd) {
            $result = text_adventure_game($state, $cmd);
            $parsed = json_decode($result, true);
            if (!$parsed || !isset($parsed['state']) || !isset($parsed['output'])) {
                $transcript[] = "ERROR: Invalid response for command '$cmd'";
                break;
            }
            $state = $parsed['state'];
            $output = $parsed['output'];
            
            if ($return_transcript_only) {
                $transcript[] = "> $cmd\n$output\n";
            } else {
                $transcript[] = "--- Command $i: $cmd ---\n$output\n";
            }
            
            // Check if game is won
            $gameState = json_decode($state, true);
            if (isset($gameState['flags']['game_won']) && $gameState['flags']['game_won'] === true) {
                $transcript[] = "\n*** VICTORY! The game has been won! ***\n";
                break;
            }
        }

        return json_encode([
            'transcript' => implode("\n", $transcript),
            'final_state_summary' => $return_transcript_only ? '' : '(state data available in transcript)'
        ]);
    }
